#include "InstCombineInternal.h"
#include "llvm/IR/PatternMatch.h"
#include "llvm/Analysis/ValueTracking.h"

using namespace llvm;
using namespace PatternMatch;

// Check if all GEPs in a PHI node have inbounds
static bool allGEPsInPHIHaveInBounds(PHINode *PN) {
  for (unsigned i = 0; i < PN->getNumIncomingValues(); ++i) {
    Value *V = PN->getIncomingValue(i);
    if (auto *GEP = dyn_cast<GetElementPtrInst>(V)) {
      if (!GEP->isInBounds())
        return false;
    } else {
      // If any incoming value is not a GEP or doesn't have inbounds, return false
      return false;
    }
  }
  return true;
}

// Helper function to check if we can safely combine GEP of PHI
static bool canCombineGEPOfPHI(GetElementPtrInst *GEP, PHINode *PN) {
  // Check if the GEP operand is a PHI of GEPs
  for (unsigned i = 0; i < PN->getNumIncomingValues(); ++i) {
    Value *V = PN->getIncomingValue(i);
    if (!isa<GetElementPtrInst>(V))
      return false;

    GetElementPtrInst *IncomingGEP = cast<GetElementPtrInst>(V);
    // All GEPs must have the same source pointer
    if (IncomingGEP->getPointerOperand() != GEP->getPointerOperand())
      return false;
  }
  return true;
}

Instruction *llvm::InstCombiner::visitGetElementPtrInst(GetElementPtrInst &GEP) {
  Value *PtrOp = GEP.getPointerOperand();

  // Check if the pointer operand is a PHI node
  if (PHINode *PN = dyn_cast<PHINode>(PtrOp)) {
    // Check if we can combine this GEP of PHI
    if (canCombineGEPOfPHI(&GEP, PN)) {
      // Create a new PHI of offsets
      PHINode *OffsetPHI = PHINode::Create(Type::getInt64Ty(PN->getContext()), 
                                          PN->getNumIncomingValues(), 
                                          "offset_phi", PN);

      // Determine if we can use inbounds for the base GEP
      bool CanUseInBounds = allGEPsInPHIHaveInBounds(PN);

      for (unsigned i = 0; i < PN->getNumIncomingValues(); ++i) {
        GetElementPtrInst *IncomingGEP = cast<GetElementPtrInst>(PN->getIncomingValue(i));
        BasicBlock *BB = PN->getIncomingBlock(i);

        // Calculate the byte offset
        int64_t Offset = 0;
        gep_type_iterator GTI = gep_type_begin(IncomingGEP);
        for (unsigned j = 1; j < IncomingGEP->getNumOperands(); ++j, ++GTI) {
          ConstantInt *CI = dyn_cast<ConstantInt>(IncomingGEP->getOperand(j));
          if (!CI) {
            // Non-constant index, can't optimize
            delete OffsetPHI;
            return nullptr;
          }
          int64_t Index = CI->getSExtValue();
          if (Index == 0) continue;

          // Get the element size
          Type *ElTy = GTI.getIndexedType();
          uint64_t ElSize = DL.getTypeAllocSize(ElTy);
          Offset += Index * ElSize;
        }

        OffsetPHI->addIncoming(ConstantInt::get(Type::getInt64Ty(PN->getContext()), Offset), BB);
      }

      // Create the base GEP with proper inbounds flag
      Value *BaseGEP;
      if (CanUseInBounds) {
        BaseGEP = GetElementPtrInst::CreateInBounds(
            Type::getInt8Ty(PN->getContext()), 
            PN->getIncomingValue(0)->stripPointerCasts(),
            OffsetPHI, "base_gep", &GEP);
      } else {
        BaseGEP = GetElementPtrInst::Create(
            Type::getInt8Ty(PN->getContext()), 
            PN->getIncomingValue(0)->stripPointerCasts(),
            OffsetPHI, "base_gep", &GEP);
      }

      // Create the final GEP for the remaining offset
      int64_t FinalOffset = 0;
      gep_type_iterator GTI = gep_type_begin(&GEP);
      for (unsigned i = 1; i < GEP.getNumOperands(); ++i, ++GTI) {
        ConstantInt *CI = dyn_cast<ConstantInt>(GEP.getOperand(i));
        if (!CI) {
          delete OffsetPHI;
          return nullptr;
        }
        int64_t Index = CI->getSExtValue();
        if (Index == 0) continue;

        Type *ElTy = GTI.getIndexedType();
        uint64_t ElSize = DL.getTypeAllocSize(ElTy);
        FinalOffset += Index * ElSize;
      }

      Value *FinalGEP = GetElementPtrInst::Create(
          Type::getInt8Ty(PN->getContext()), 
          BaseGEP,
          ConstantInt::get(Type::getInt64Ty(PN->getContext()), FinalOffset),
          "final_gep", &GEP);

      return ReplaceInstUsesWith(GEP, FinalGEP);
    }
  }

  return nullptr;
}
